import React, { useState } from 'react'
import Head from 'next/head'
import raceDayCalc from './api/raceDayCalc'

const About = () => {

  const [ raceDay, setRaceDay ] = useState("Jan 01, 2020")

  // const raceDayChange = (e) => {
  //   setRaceDay(e.target.value);
  // }

  const raceDayStart = (e) => {
    e.preventDefault();
    console.log(raceDay)
  }

  return(

    <div>

    <Head>
      <title>About</title>
      <link rel="icon" href="" />
    </Head>

    <div>
      <form onSubmit={raceDayStart}>
        <label>Race Day</label>
        <input type="text" value={raceDay} onChange={e => setRaceDay(e.target.value)}></input>
        <button type="submit">Submit</button>
      </form>
    </div>

    </div>
  )
}

export default About
